+    cx: &Cx,
+    config: &mcp_agent_mail_core::Config,
+) -> Result<(), HttpHealthProbeFailure> {
+    let deadline = Instant::now() + STARTUP_READINESS_SELF_PROBE_TIMEOUT;
+    let mut last_failure = HttpHealthProbeFailure::Timeout { elapsed_ms: 0 };
